// CypherLexerInit initializes any static state used to implement CypherLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewCypherLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func CypherLexerInit() {
	staticData := &CypherLexerLexerStaticData
	staticData.once.Do(cypherlexerLexerInit)
}

// NewCypherLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewCypherLexer(input antlr.CharStream) *CypherLexer {
	CypherLexerInit()
	l := new(CypherLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &CypherLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "Cypher.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

